[{'connection': '($ch, CURLOPT_NOBODY, true);\n    curl_setopt($ch, CURLOPT_TIMEOUT, 10);\n    curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);\n    \n    $response = curl_exec($ch);\n    $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);\n    curl_close($ch);\n    \n    // Jeśli otrzymaliśmy kod 2xx lub 3xx, instancja jest dostępna\n    return $httpCode >= 200 && $httpCode < 400;', 'notify_admin': "\\n        $message = 'Następujące instancje demo są niedostępne:', 'n;\n        foreach ($down_instances as $instance) {\n            $message .='Instance $instance is DOWN';\n        }\n        // Tutaj można dodać wysyłanie powiadomienia email lub SMS\n        echo $message, 'n;", 'get_instance_urls': "[\n        'agencja' => 'https://agencja.flowquest.pl',\n        'beauty' => 'https://beauty.flowquest.pl',\n        'ecommerce' => 'https://ecommerce.flowquest.pl',\n        'eventy' => 'https://eventy.flowquest.pl',\n        'gastronomia' => 'https://gastronomia.flowquest.pl',\n        'hotel' => 'https://hotel.flowquest.pl',\n        'kursy' => 'https://kursy.flowquest.pl',\n        'logistyka' => 'https://logistyka.flowquest.pl',\n        'medycyna' => 'https://medycyna.flowquest.pl',\n        'nieruchomosci' => 'https://nieruchomosci.flowquest.pl',\n        'oze' => 'https://oze.flowquest.pl',\n        'rekrutacja' => 'https://rekrutacja.flowquest.pl',\n        'serwiswww' => 'https://serwiswww.flowquest.pl',\n        'warsztat' => 'https://warsztat.flowquest.pl'\n    ];"}, {'$down_instances': '[];\n        foreach ($instances as $name => $url) {\n            echo "Checking $name ($url)... ";\n            if (!check_instance($url)) {\n                $down_instances[] = $name;\n                echo "DOWN", "n;\n            } else {\n                echo "UP", "n;\n            }\n        }\n        \n        if (count($down_instances) > 0) {\n            notify_admin($down_instances);\n        }\n        \n        echo "Monitoring completed. Down instances: " . count($down_instances), "n;\n        exit;'}]